import java.util.*;

public class BFSShortestPath {

    // Returns shortest distance from src to dst in an unweighted graph.
    // adjacencyList: Map<node, List<neighbour>>
    public static int bfs(Map<Integer, List<Integer>> graph, int src, int dst) {
        if (src == dst) return 0;

        Queue<Integer> queue = new LinkedList<>();
        Set<Integer>   visited = new HashSet<>();

        queue.offer(src);
        visited.add(src);
        int steps = 0;

        while (!queue.isEmpty()) {
            int size = queue.size();        // nodes at current level
            steps++;

            for (int i = 0; i < size; i++) {
                int node = queue.poll();

                for (int neighbor : graph.getOrDefault(node, List.of())) {
                    if (neighbor == dst) return steps;
                    if (!visited.contains(neighbor)) {
                        visited.add(neighbor);
                        queue.offer(neighbor);
                    }
                }
            }
        }
        return -1; // dst unreachable
    }

    public static void main(String[] args) {
        Map<Integer, List<Integer>> g = new HashMap<>();
        g.put(1, List.of(2, 3));
        g.put(2, List.of(4));
        g.put(3, List.of(4, 5));
        g.put(4, List.of(6));
        g.put(5, List.of(6));

        System.out.println(bfs(g, 1, 6)); // 3  (1→3→5→6 or 1→2→4→6)
        System.out.println(bfs(g, 1, 5)); // 2  (1→3→5)
    }
}

import java.util.*;

public class CycleDetection {

    // 0 = unvisited, 1 = in current DFS path (grey), 2 = fully processed (black)
    private int[] color;
    private Map<Integer, List<Integer>> graph;

    public boolean hasCycle(int n, int[][] edges) {
        graph = new HashMap<>();
        color = new int[n];

        for (int[] e : edges)
            graph.computeIfAbsent(e[0], k -> new ArrayList<>()).add(e[1]);

        for (int i = 0; i < n; i++)
            if (color[i] == 0 && dfs(i)) return true;

        return false;
    }

    private boolean dfs(int node) {
        color[node] = 1; // grey: on the current path

        for (int nb : graph.getOrDefault(node, List.of())) {
            if (color[nb] == 1) return true;  // back-edge → cycle!
            if (color[nb] == 0 && dfs(nb)) return true;
        }

        color[node] = 2; // black: fully explored, no cycle through here
        return false;
    }

    public static void main(String[] args) {
        CycleDetection cd = new CycleDetection();
        // 0→1→2→0 forms a cycle
        System.out.println(cd.hasCycle(3, new int[][]{{0,1},{1,2},{2,0}})); // true
        System.out.println(cd.hasCycle(3, new int[][]{{0,1},{1,2}}));       // false
    }
}

import java.util.*;

public class TopologicalSort {

    // Kahn's Algorithm: BFS-based topological ordering
    // Returns empty list if a cycle exists (no valid ordering)
    public static List<Integer> topoSort(int n, int[][] edges) {
        List<List<Integer>> adj = new ArrayList<>();
        int[] inDegree = new int[n];

        for (int i = 0; i < n; i++) adj.add(new ArrayList<>());

        for (int[] e : edges) {
            adj.get(e[0]).add(e[1]);
            inDegree[e[1]]++;          // count incoming edges
        }

        Queue<Integer> queue = new LinkedList<>();
        for (int i = 0; i < n; i++)
            if (inDegree[i] == 0) queue.offer(i); // start with nodes that have no prerequisites

        List<Integer> order = new ArrayList<>();

        while (!queue.isEmpty()) {
            int node = queue.poll();
            order.add(node);

            for (int nb : adj.get(node)) {
                if (--inDegree[nb] == 0)   // all prerequisites of nb are done
                    queue.offer(nb);
            }
        }

        return order.size() == n ? order : List.of(); // empty = cycle detected
    }

    public static void main(String[] args) {
        // Course schedule: 0→2, 1→2, 1→3, 2→4, 3→4
        // Must take 0 and 1 before 2; 1 and 2 before 4, etc.
        int[][] edges = {{0,2},{1,2},{1,3},{2,4},{3,4}};
        System.out.println(topoSort(5, edges)); // e.g. [0,1,2,3,4]
    }
}

import java.util.*;

public class Dijkstra {

    public static int[] shortestPaths(int n, int[][] edges, int src) {
        // Build adjacency list: node → [(neighbor, weight), ...]
        Map<Integer, List<int[]>> graph = new HashMap<>();
        for (int[] e : edges)
            graph.computeIfAbsent(e[0], k -> new ArrayList<>()).add(new int[]{e[1], e[2]});

        int[] dist = new int[n];
        Arrays.fill(dist, Integer.MAX_VALUE);
        dist[src] = 0;

        // Min-heap: [distance, node]
        PriorityQueue<int[]> pq = new PriorityQueue<>(Comparator.comparingInt(a -> a[0]));
        pq.offer(new int[]{0, src});

        while (!pq.isEmpty()) {
            int[] curr = pq.poll();
            int d = curr[0], u = curr[1];

            if (d > dist[u]) continue; // stale entry — skip

            for (int[] edge : graph.getOrDefault(u, List.of())) {
                int v = edge[0], w = edge[1];
                int newDist = dist[u] + w;
                if (newDist < dist[v]) {
                    dist[v] = newDist;
                    pq.offer(new int[]{newDist, v});
                }
            }
        }
        return dist;
    }

    public static void main(String[] args) {
        // Graph: 0→1 (w=4), 0→2 (w=1), 2→1 (w=2), 1→3 (w=1), 2→3 (w=5)
        int[][] edges = {{0,1,4},{0,2,1},{2,1,2},{1,3,1},{2,3,5}};
        int[] d = shortestPaths(4, edges, 0);
        System.out.println(Arrays.toString(d)); // [0, 3, 1, 4]
        // 0→2 costs 1; 0→2→1 costs 3 (not 0→1=4); 0→2→1→3 costs 4
    }
}

public class UnionFind {

    private int[] parent;
    private int[] rank;
    private int components;

    public UnionFind(int n) {
        parent = new int[n];
        rank   = new int[n];
        components = n;
        for (int i = 0; i < n; i++) parent[i] = i; // each node is its own leader
    }

    // Find: returns the root of x's component (with path compression)
    public int find(int x) {
        if (parent[x] != x)
            parent[x] = find(parent[x]); // path compression — flatten the tree
        return parent[x];
    }

    // Union: merge the components containing x and y
    // Returns true if they were in DIFFERENT components (a merge happened)
    public boolean union(int x, int y) {
        int rx = find(x), ry = find(y);
        if (rx == ry) return false; // already connected

        // Union by rank: attach smaller tree under larger tree
        if      (rank[rx] < rank[ry]) parent[rx] = ry;
        else if (rank[rx] > rank[ry]) parent[ry] = rx;
        else { parent[ry] = rx; rank[rx]++; }

        components--;
        return true;
    }

    public boolean connected(int x, int y) { return find(x) == find(y); }
    public int     count()                 { return components; }

    public static void main(String[] args) {
        UnionFind uf = new UnionFind(6); // nodes 0..5
        uf.union(0, 1);  // {0,1}, {2}, {3}, {4}, {5}
        uf.union(1, 2);  // {0,1,2}, {3}, {4}, {5}
        uf.union(3, 4);  // {0,1,2}, {3,4}, {5}
        System.out.println(uf.count());         // 3
        System.out.println(uf.connected(0, 2)); // true
        System.out.println(uf.connected(0, 3)); // false
    }
}

